function Home() {
  return (
    <div className="page-center">
      <div className="card">
        <h1>Campus Connect</h1>
        <p style={{ textAlign: "center" }}>
          Senior–Junior Interaction Platform
        </p>

        <a className="btn" href="/login">Login</a>
        <a className="link" href="/register">Register</a>
      </div>
    </div>
  );
}

export default Home;
